/**
 * ListenerFatigue — [1:25-1:33]
 * Coined term card. "LISTENER FATIGUE" — the white noise problem.
 * Screenshot-worthy moment, parallel to InterrogationShadows.
 */
import React from "react";
import {
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { COLOR, FONT_WEIGHT, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

export const ListenerFatigue: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const easeOut = (t: number) => 1 - Math.pow(1 - t, 3);

  // ── "LISTENER" slides down ────────────────────────────────────────────────
  const line1Y  = spring({ frame, fps, from: -20, to: 0, config: SPRING.snappy });
  const line1Op = interpolate(frame, [0, 10], [0, 1], { extrapolateRight: "clamp" });

  // ── "FATIGUE" springs up with bounce ─────────────────────────────────────
  const line2Spring = spring({ frame: Math.max(0, frame - 5), fps, from: 0, to: 1, config: SPRING.bouncy });
  const line2Scale  = interpolate(line2Spring, [0, 0.65, 1], [0.7, 1.1, 1]);
  const line2Op     = interpolate(frame, [5, 16], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

  // ── Sub-line ──────────────────────────────────────────────────────────────
  const subOp = interpolate(frame, [20, 30], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
  const subY  = spring({ frame: Math.max(0, frame - 20), fps, from: 10, to: 0, config: SPRING.smooth });

  // ── Rule ──────────────────────────────────────────────────────────────────
  const ruleScale = interpolate(frame, [28, 40], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp", easing: easeOut,
  });

  // ── Fix line ──────────────────────────────────────────────────────────────
  const fixOp = interpolate(frame, [36, 46], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });
  const fixX  = spring({ frame: Math.max(0, frame - 36), fps, from: -16, to: 0, config: SPRING.smooth });

  return (
    <GraphicWrapper>
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 6 }}>

        {/* ── LISTENER ── */}
        <div style={{ opacity: line1Op, transform: `translateY(${line1Y}px)` }}>
          <span style={{
            fontSize: 72,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textPrimary,
            letterSpacing: "0.06em",
            textTransform: "uppercase",
            display: "block",
            textAlign: "center",
          }}>
            LISTENER
          </span>
        </div>

        {/* ── FATIGUE ── */}
        <div style={{ opacity: line2Op, transform: `scale(${line2Scale})` }}>
          <span style={{
            fontSize: 110,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.ringPrimary,
            letterSpacing: "-0.02em",
            textTransform: "uppercase",
            display: "block",
            textAlign: "center",
            lineHeight: 1,
          }}>
            FATIGUE
          </span>
        </div>

        {/* ── Sub-line ── */}
        <div style={{
          opacity: subOp,
          transform: `translateY(${subY}px)`,
          marginTop: 16,
          textAlign: "center",
        }}>
          <span style={{
            fontSize: 20,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textMuted,
            letterSpacing: "0.03em",
          }}>
            White noise your audience can't ignore
          </span>
        </div>

        {/* ── Rule ── */}
        <div style={{
          width: 52,
          height: 1.5,
          background: "rgba(29,29,31,0.15)",
          margin: "14px 0 10px",
          transform: `scaleX(${ruleScale})`,
          transformOrigin: "center center",
        }} />

        {/* ── Fix ── */}
        <div style={{
          opacity: fixOp,
          transform: `translateX(${fixX}px)`,
          display: "flex",
          alignItems: "center",
          gap: 12,
        }}>
          <span style={{
            fontSize: 13,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.ringSecondary,
            letterSpacing: "0.2em",
            textTransform: "uppercase",
          }}>
            KILL THE HUM
          </span>
          <span style={{ fontSize: 13, fontWeight: FONT_WEIGHT.extraBold, color: COLOR.textSecondary }}>
            →
          </span>
          <span style={{
            fontSize: 18,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textPrimary,
            letterSpacing: "0.03em",
          }}>
            Fridges. Fans. Air con.
          </span>
        </div>

      </div>
    </GraphicWrapper>
  );
};

/**
 * ThreeAudioFixes — [1:10-1:45]
 * Three audio fixes stacking in sequentially.
 * 6 seconds (180 frames @ 30fps).
 */
import React from "react";
import {
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { COLOR, FONT_WEIGHT, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

const FIXES = [
  {
    num:      "①",
    category: "DISTANCE",
    fix:      "Bring the mic closer.",
    detail:   "Voice becomes thick and intimate.",
  },
  {
    num:      "②",
    category: "SURFACES",
    fix:      "Cushions kill the pinball bounce.",
    detail:   "Hard walls = echoey room.",
  },
  {
    num:      "③",
    category: "HUM",
    fix:      "Remove white noise sources.",
    detail:   "Stop listener fatigue before it starts.",
  },
];

const ROW_DELAYS = [8, 52, 96];

const FixRow: React.FC<{ fix: typeof FIXES[number]; delay: number }> = ({
  fix,
  delay,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const slideX = spring({
    frame: Math.max(0, frame - delay),
    fps,
    from: -40,
    to: 0,
    config: SPRING.smooth,
  });

  const rowOp = interpolate(frame, [delay, delay + 14], [0, 1], {
    extrapolateLeft: "clamp",
    extrapolateRight: "clamp",
  });

  return (
    <div style={{
      display: "flex",
      alignItems: "center",
      gap: 22,
      opacity: rowOp,
      transform: `translateX(${slideX}px)`,
    }}>

      {/* Number badge */}
      <span style={{
        fontSize: 52,
        fontWeight: FONT_WEIGHT.extraBold,
        color: COLOR.ringSecondary,
        lineHeight: 1,
        minWidth: 48,
        textAlign: "center",
      }}>
        {fix.num}
      </span>

      {/* Category */}
      <span style={{
        fontSize: 28,
        fontWeight: FONT_WEIGHT.extraBold,
        color: COLOR.ringPrimary,
        letterSpacing: "0.1em",
        minWidth: 130,
      }}>
        {fix.category}
      </span>

      {/* Arrow */}
      <span style={{
        fontSize: 20,
        color: COLOR.textSecondary,
        fontWeight: FONT_WEIGHT.extraBold,
      }}>
        →
      </span>

      {/* Fix text */}
      <div style={{ display: "flex", flexDirection: "column", gap: 2 }}>
        <span style={{
          fontSize: 24,
          fontWeight: FONT_WEIGHT.extraBold,
          color: COLOR.textPrimary,
          letterSpacing: "0.01em",
          lineHeight: 1.2,
        }}>
          {fix.fix}
        </span>
        <span style={{
          fontSize: 18,
          fontWeight: FONT_WEIGHT.extraBold,
          color: COLOR.textMuted,
          letterSpacing: "0.03em",
        }}>
          {fix.detail}
        </span>
      </div>

    </div>
  );
};

export const ThreeAudioFixes: React.FC = () => {
  const frame = useCurrentFrame();

  const headerOp = interpolate(frame, [0, 10], [0, 1], { extrapolateRight: "clamp" });

  return (
    <GraphicWrapper>
      <div style={{ display: "flex", flexDirection: "column", gap: 12, alignItems: "flex-start" }}>

        {/* Header */}
        <div style={{ opacity: headerOp, marginBottom: 18 }}>
          <span style={{
            fontSize: 13,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textSecondary,
            letterSpacing: "0.2em",
            textTransform: "uppercase",
          }}>
            3 AUDIO FIXES — NO NEW GEAR REQUIRED
          </span>
        </div>

        {/* Rows */}
        {FIXES.map((fix, i) => (
          <FixRow key={i} fix={fix} delay={ROW_DELAYS[i]} />
        ))}

      </div>
    </GraphicWrapper>
  );
};

/**
 * NinetyDays — [1:42-1:55]
 * "90 DAYS" struck through → arrow → "1 AFTERNOON"
 * Animated strikethrough draws across, then the replacement drops in.
 */
import React from "react";
import {
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { COLOR, FONT_WEIGHT, SPRING } from "./brand";
import { GraphicWrapper } from "./GraphicWrapper";

export const NinetyDays: React.FC = () => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const easeOut = (t: number) => 1 - Math.pow(1 - t, 3);

  // ── "90 DAYS" springs in ──────────────────────────────────────────────────
  const topSpring = spring({ frame, fps, from: 0, to: 1, config: SPRING.bouncy });
  const topScale  = interpolate(topSpring, [0, 0.65, 1], [0.7, 1.06, 1]);
  const topOp     = interpolate(frame, [0, 10], [0, 1], { extrapolateRight: "clamp" });

  // ── Strikethrough line draws left → right ─────────────────────────────────
  const strikeX = interpolate(frame, [16, 32], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp", easing: easeOut,
  });
  const strikeOp = interpolate(frame, [16, 20], [0, 1], {
    extrapolateLeft: "clamp", extrapolateRight: "clamp",
  });

  // ── Arrow ─────────────────────────────────────────────────────────────────
  const arrowY  = spring({ frame: Math.max(0, frame - 28), fps, from: -10, to: 0, config: SPRING.smooth });
  const arrowOp = interpolate(frame, [28, 36], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

  // ── "1 AFTERNOON" springs in ──────────────────────────────────────────────
  const botSpring = spring({ frame: Math.max(0, frame - 36), fps, from: 0, to: 1, config: SPRING.bouncy });
  const botScale  = interpolate(botSpring, [0, 0.65, 1], [0.7, 1.06, 1]);
  const botOp     = interpolate(frame, [36, 46], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

  // ── Label ─────────────────────────────────────────────────────────────────
  const labelOp = interpolate(frame, [50, 60], [0, 1], { extrapolateLeft: "clamp", extrapolateRight: "clamp" });

  return (
    <GraphicWrapper>
      <div style={{ display: "flex", flexDirection: "column", alignItems: "center", gap: 12 }}>

        {/* ── 90 DAYS (dimmed + strikethrough) ── */}
        <div style={{
          position: "relative",
          opacity: topOp,
          transform: `scale(${topScale})`,
          display: "inline-flex",
          alignItems: "baseline",
          gap: 14,
        }}>
          <span style={{
            fontSize: 110,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textPrimary,
            opacity: 0.35,
            letterSpacing: "-0.04em",
            lineHeight: 1,
          }}>
            90
          </span>
          <span style={{
            fontSize: 44,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textPrimary,
            opacity: 0.35,
            letterSpacing: "0.06em",
          }}>
            DAYS
          </span>

          {/* Animated strikethrough */}
          <div style={{
            position: "absolute",
            top: "50%",
            left: -6,
            right: -6,
            height: 5,
            background: COLOR.ringPrimary,
            borderRadius: 2,
            opacity: strikeOp,
            transform: `scaleX(${strikeX})`,
            transformOrigin: "left center",
          }} />
        </div>

        {/* ── Down arrow ── */}
        <div style={{
          opacity: arrowOp,
          transform: `translateY(${arrowY}px)`,
          fontSize: 30,
          color: COLOR.textSecondary,
          lineHeight: 1,
        }}>
          ↓
        </div>

        {/* ── 1 AFTERNOON ── */}
        <div style={{
          opacity: botOp,
          transform: `scale(${botScale})`,
          display: "inline-flex",
          alignItems: "baseline",
          gap: 14,
        }}>
          <span style={{
            fontSize: 110,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.ringSecondary,
            letterSpacing: "-0.04em",
            lineHeight: 1,
          }}>
            1
          </span>
          <span style={{
            fontSize: 44,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.ringSecondary,
            letterSpacing: "0.06em",
          }}>
            AFTERNOON
          </span>
        </div>

        {/* ── Label ── */}
        <div style={{ opacity: labelOp, marginTop: 10 }}>
          <span style={{
            fontSize: 14,
            fontWeight: FONT_WEIGHT.extraBold,
            color: COLOR.textMuted,
            letterSpacing: "0.22em",
            textTransform: "uppercase",
          }}>
            BATCH CONTENT BLUEPRINT
          </span>
        </div>

      </div>
    </GraphicWrapper>
  );
};

