/**
 * GraphicWrapper — shared shell for every composition.
 * Handles: brand background, font, spring scale-in, blur dissolve-out.
 *
 * Banding fix: the gradient lives on a separate overlay layer that fades to
 * flat BEFORE the blur starts. By the time the blur fires, the background is
 * a clean flat colour — no gradient banding artefacts.
 */
import React from "react";
import {
  AbsoluteFill,
  interpolate,
  spring,
  useCurrentFrame,
  useVideoConfig,
} from "remotion";
import { loadFont } from "@remotion/google-fonts/Montserrat";
import { BG_GRADIENT, COLOR, SPRING } from "./brand";

const { fontFamily } = loadFont("normal", {
  weights: ["400", "600", "700", "800"],
  subsets: ["latin"],
});

export const GraphicWrapper: React.FC<{ children: React.ReactNode }> = ({
  children,
}) => {
  const frame = useCurrentFrame();
  const { fps, durationInFrames } = useVideoConfig();

  const dissolveStart = durationInFrames - 24; // 0.8s before end

  // ── Gradient overlay fades OUT before blur starts ─────────────────────────
  // Completes 4 frames before dissolveStart so background is fully flat
  // by the time any blur is applied — eliminates banding.
  const gradientOp = interpolate(
    frame,
    [dissolveStart - 16, dissolveStart - 4],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  // ── Blur dissolve — fires on flat background, no banding ─────────────────
  const blurPx = interpolate(
    frame,
    [dissolveStart, durationInFrames],
    [0, 24],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );
  const dissolveOp = interpolate(
    frame,
    [dissolveStart, durationInFrames],
    [1, 0],
    { extrapolateLeft: "clamp", extrapolateRight: "clamp" }
  );

  // ── Content fade-in + spring scale ───────────────────────────────────────
  const fadeIn = interpolate(frame, [0, 8], [0, 1], {
    extrapolateRight: "clamp",
  });
  const scale = spring({
    frame,
    fps,
    from: 0.84,
    to: 1,
    config: SPRING.snappy,
  });

  return (
    <AbsoluteFill
      style={{
        background: COLOR.bgCenter, // flat base colour — safe to blur
        fontFamily,
        filter: `blur(${blurPx}px)`,
        opacity: dissolveOp,
      }}
    >
      {/* Gradient overlay — fades out cleanly before blur fires */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          background: BG_GRADIENT,
          opacity: gradientOp,
        }}
      />

      {/* Content */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          transform: `scale(${scale})`,
          opacity: fadeIn,
        }}
      >
        {children}
      </div>
    </AbsoluteFill>
  );
};

