        style={{
          position: "absolute",
          inset: 0,
          background: BG_GRADIENT,
          opacity: gradientOp,
        }}
      />

      {/* Content */}
      <div
        style={{
          position: "absolute",
          inset: 0,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          transform: `scale(${scale})`,
          opacity: fadeIn,
        }}
      >
        {children}
      </div>
    </AbsoluteFill>
  );
};

